def rotate_grid(grid, n):
    rotated = [[0] * n for i in range(n)] 
    for i in range(n):
        for j in range(n):
            rotated[j][n - i - 1] = grid[i][j]
    return rotated

n = int(input())
grid = []

for i in range(n):
    row = [int(x) for x in input().split()]
    grid.append(row)

rotated_grid = rotate_grid(grid, n)

for row in rotated_grid:
    for num in row:
        print(num, end=" ")
    print()
